// Mapeo columnas card 66793 + filtro últimos 30 días
// Columnas reales: titulo, tipo_de_servicio, journey, fase_actual, codigo_bia,
// operador_de_red, contratista, fecha_programada, mercado,
// costos_bia, service_cost, material_cost, transport_cost, other_cost, total_cost

let rows = [];
if ($input.all().length > 1) {
  rows = $input.all().map(i => i.json);
} else {
  const raw = $input.first().json;
  rows = Array.isArray(raw) ? raw : (raw.data ? raw.data : [raw]);
}

const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 30);

const result = [];
for (const r of rows) {
  const titulo = (r.titulo || '').toString().trim();
  if (!titulo) continue;

  const fechaRaw = r.fecha_programada || '';
  if (!fechaRaw) continue;
  if (new Date(fechaRaw) < cutoff) continue;
  const fecha = fechaRaw.toString().split('T')[0];

  const contratistaNombre = (r.contratista || 'SIN_CONTRATISTA').toString().trim();
  const contratistaId = contratistaNombre
    .toUpperCase()
    .replace(/\s+/g, '_')
    .replace(/[^A-Z0-9_]/g, '');

  result.push({
    json: {
      tx_id_fuente:       titulo,
      contratista_id:     contratistaId,
      contratista_nombre: contratistaNombre,
      tipo_servicio:      (r.tipo_de_servicio || '').toString().trim(),
      zona:               (r.mercado || '').toString().trim(),
      or_nombre:          (r.operador_de_red || '').toString().trim(),
      ot_id:              titulo,
      fecha_tx:           fecha,
      costo_unitario:     Number(r.total_cost || 0),
      costo_total:        Number(r.total_cost || 0),
      tiene_acta_cierre:  r.fase_actual === 'Cierre Exitoso',
      notas_ot:           (r.journey || '').toString().trim()
    }
  });
}

return result.length > 0 ? result : [{ json: { sin_datos: true, count: 0 } }];

// Consolida TODOS los ítems en UN solo INSERT batch → 1 query en lugar de N
const items = $input.all();

if (items.length === 0 || items[0].json.sin_datos) {
  return [{ json: { sin_datos: true, count: 0 } }];
}

const esc = s => (s || '').toString().replace(/'/g, "''");

// Deduplicar por tx_id_fuente — Metabase puede devolver la misma OT varias veces
const seen = new Map();
for (const item of items) {
  const key = item.json.tx_id_fuente;
  if (!key) continue;
  // Mantener la última ocurrencia (mayor costo_total si hay discrepancia)
  if (!seen.has(key) || Number(item.json.costo_total) > Number(seen.get(key).json.costo_total)) {
    seen.set(key, item);
  }
}
const unique = Array.from(seen.values());

if (unique.length === 0) {
  return [{ json: { sin_datos: true, count: 0 } }];
}

const values = unique.map(item => {
  const r = item.json;
  return `('${esc(r.tx_id_fuente)}','${esc(r.contratista_id)}','${esc(r.contratista_nombre)}','${esc(r.tipo_servicio)}','${esc(r.zona)}','${esc(r.or_nombre)}','${esc(r.ot_id)}','${esc(r.fecha_tx)}'::DATE,${Number(r.costo_unitario)},${Number(r.costo_total)},${!!r.tiene_acta_cierre},'${esc(r.notas_ot)}',false)`;
}).join(',');

const sql = `INSERT INTO opex_transactions (tx_id_fuente,contratista_id,contratista_nombre,tipo_servicio,zona,or_nombre,ot_id,fecha_tx,costo_unitario,costo_total,tiene_acta_cierre,notas_ot,procesado) VALUES ${values} ON CONFLICT (tx_id_fuente) DO UPDATE SET costo_total=EXCLUDED.costo_total,costo_unitario=EXCLUDED.costo_unitario,tiene_acta_cierre=EXCLUDED.tiene_acta_cierre,contratista_nombre=EXCLUDED.contratista_nombre,zona=EXCLUDED.zona,or_nombre=EXCLUDED.or_nombre WHERE opex_transactions.procesado=false;`;

return [{ json: { sql, count: unique.length, duplicados_removidos: items.length - unique.length } }];

const items = $input.all();
const alerts = [];

for (const item of items) {
  const tx = item.json;

  // A13: contratista operando en OR sin tarifa pactada
  if (tx.costo_total > 0 && !tx.tarifa_vigente && tx.or_nombre && tx.contratista_id !== 'BIA') {
    alerts.push({ json: {
      codigo_alerta: 'A13', severidad: 'alta',
      tx_id: tx.tx_id, contratista_id: tx.contratista_id,
      contratista_nombre: tx.contratista_nombre || tx.contratista_id,
      tipo_servicio: tx.tipo_servicio, zona: tx.zona || 'Sin zona',
      ot_id: tx.ot_id,
      valor_observado: tx.costo_total, valor_esperado: null,
      narrativa_corta: `Sin tarifa pactada para ${tx.contratista_id} en OR ${tx.or_nombre} — operación fuera de zona o tarifario no cargado`,
      accion_requerida: 'revision_contrato'
    }});
  }

  if (tx.tarifa_vigente && tx.delta_vs_tarifa_pct !== null) {
    const delta = Number(tx.delta_vs_tarifa_pct);
    const tolerancia = Number(tx.tolerancia_pct || 3);

    if (delta > 15) {
      alerts.push({ json: {
        codigo_alerta: 'A3', severidad: 'alta',
        tx_id: tx.tx_id, contratista_id: tx.contratista_id,
        contratista_nombre: tx.contratista_nombre || tx.contratista_id,
        tipo_servicio: tx.tipo_servicio, zona: tx.zona || 'Sin zona',
        ot_id: tx.ot_id,
        valor_observado: tx.costo_unitario, valor_esperado: tx.tarifa_vigente,
        delta_absoluto: tx.costo_unitario - tx.tarifa_vigente,
        delta_pct: delta, zscore: null,
        query_evidencia: `SELECT * FROM opex_transactions WHERE tx_id_fuente = '${tx.tx_id_fuente}'`,
        narrativa_corta: `Costo ${delta.toFixed(1)}% sobre tarifa vigente ($${Number(tx.tarifa_vigente).toLocaleString('es-CO')})`,
        tarifario_version: tx.tarifa_version,
        accion_requerida: 'correo_borrador'
      }});
    } else if (delta > 5) {
      alerts.push({ json: {
        codigo_alerta: 'A2', severidad: 'media',
        tx_id: tx.tx_id, contratista_id: tx.contratista_id,
        contratista_nombre: tx.contratista_nombre || tx.contratista_id,
        tipo_servicio: tx.tipo_servicio, zona: tx.zona || 'Sin zona',
        ot_id: tx.ot_id,
        valor_observado: tx.costo_unitario, valor_esperado: tx.tarifa_vigente,
        delta_absoluto: tx.costo_unitario - tx.tarifa_vigente,
        delta_pct: delta, zscore: null,
        narrativa_corta: `Costo ${delta.toFixed(1)}% sobre tarifa pactada`,
        tarifario_version: tx.tarifa_version,
        accion_requerida: 'ticket'
      }});
    } else if (delta > tolerancia) {
      alerts.push({ json: {
        codigo_alerta: 'A1', severidad: 'baja',
        tx_id: tx.tx_id, contratista_id: tx.contratista_id,
        contratista_nombre: tx.contratista_nombre || tx.contratista_id,
        tipo_servicio: tx.tipo_servicio, zona: tx.zona || 'Sin zona',
        ot_id: tx.ot_id,
        valor_observado: tx.costo_unitario, valor_esperado: tx.tarifa_vigente,
        delta_absoluto: tx.costo_unitario - tx.tarifa_vigente,
        delta_pct: delta, zscore: null,
        narrativa_corta: `Desvío leve (${delta.toFixed(1)}%) vs tarifa — solo log`,
        accion_requerida: 'log'
      }});
    }
  }

  if (tx.tiene_acta_cierre === false && tx.ot_id) {
    const diasSinSoporte = (new Date() - new Date(tx.fecha_tx)) / (1000 * 60 * 60 * 24);
    if (diasSinSoporte >= 7) {
      alerts.push({ json: {
        codigo_alerta: 'A7', severidad: 'media',
        tx_id: tx.tx_id, contratista_id: tx.contratista_id,
        contratista_nombre: tx.contratista_nombre || tx.contratista_id,
        tipo_servicio: tx.tipo_servicio, zona: tx.zona || 'Sin zona',
        ot_id: tx.ot_id,
        valor_observado: diasSinSoporte, valor_esperado: 7,
        narrativa_corta: `OT ${tx.ot_id} lleva ${Math.floor(diasSinSoporte)} días sin acta de cierre`,
        accion_requerida: 'correo_operaciones'
      }});
    }
  }

  if (tx.ejecutado_mtd && tx.budget_mes && Number(tx.budget_mes) > 0) {
    const desvio = ((Number(tx.ejecutado_mtd) - Number(tx.budget_mes)) / Number(tx.budget_mes)) * 100;
    if (desvio > 10) {
      alerts.push({ json: {
        codigo_alerta: 'A9', severidad: 'alta',
        tx_id: tx.tx_id, contratista_id: tx.contratista_id,
        contratista_nombre: tx.contratista_nombre || tx.contratista_id,
        zona: tx.zona || 'Sin zona',
        valor_observado: tx.ejecutado_mtd, valor_esperado: tx.budget_mes,
        delta_pct: desvio,
        narrativa_corta: `Ejecutado MTD supera budget en ${desvio.toFixed(1)}%`,
        accion_requerida: 'escalamiento'
      }});
    } else if (desvio > 5) {
      alerts.push({ json: {
        codigo_alerta: 'A8', severidad: 'media',
        tx_id: tx.tx_id, contratista_id: tx.contratista_id,
        contratista_nombre: tx.contratista_nombre || tx.contratista_id,
        zona: tx.zona || 'Sin zona',
        valor_observado: tx.ejecutado_mtd, valor_esperado: tx.budget_mes,
        delta_pct: desvio,
        narrativa_corta: `Ejecución MTD ${desvio.toFixed(1)}% sobre budget`,
        accion_requerida: 'slack'
      }});
    }
  }
}

return alerts.length > 0 ? alerts : [{ json: { sin_alertas: true, total: 0 } }];

const allAlerts = $input.all();
const urgentes = allAlerts.filter(a => ['alta','critica'].includes(a.json.severidad));
if (urgentes.length === 0) return [];

const resumen = urgentes.slice(0, 5).map(a => {
  const ico = a.json.severidad === 'critica' ? '🔴' : '🟠';
  return `${ico} [${a.json.codigo_alerta}] ${a.json.contratista_nombre || a.json.contratista_id} — ${a.json.zona} | ${a.json.narrativa_corta}`;
}).join('\n');

return [{ json: { urgentes_count: urgentes.length, resumen_texto: resumen } }];
